40	static void fz_new_style_context(fz_context *ctx)
41	{
42		if (ctx)
43		{
44			ctx->style = fz_malloc_struct(ctx, fz_style_context);
45			ctx->style->refs = 1;
46			ctx->style->user_css = NULL;
47			ctx->style->use_document_css = 1;
48		}
49	}
