51	static fz_style_context *fz_keep_style_context(fz_context *ctx)
52	{
53		if (!ctx)
54			return NULL;
55		return fz_keep_imp(ctx, ctx->style, &ctx->style->refs);
56	}
57	
58	static void fz_drop_style_context(fz_context *ctx)
59	{
60		if (!ctx)
61			return;
62		if (fz_drop_imp(ctx, ctx->style, &ctx->style->refs))
63		{
64			fz_free(ctx, ctx->style->user_css);
65			fz_free(ctx, ctx->style);
66		}
