92	void fz_load_user_css(fz_context *ctx, const char *filename)
93	{
94		fz_buffer *buf = NULL;
95		fz_var(buf);
96		fz_try(ctx)
97		{
98			buf = fz_read_file(ctx, filename);
99			fz_set_user_css(ctx, fz_string_from_buffer(ctx, buf));
100		}
101		fz_always(ctx)
102		{
103			fz_drop_buffer(ctx, buf);
104		}
105		fz_catch(ctx)
106		{
107			fz_report_error(ctx);
108			fz_warn(ctx, "cannot read user css file");
109		}
